const fs = require('fs');
const data = JSON.parse(fs.readFileSync('lint_full.json', 'utf8'));

const fileErrors = {};

data.forEach(f => {
    if (f.errorCount > 0) {
        const fileName = f.filePath.split('\\').pop();
        const errors = f.messages.filter(m => m.severity === 2);

        if (!fileErrors[fileName]) {
            fileErrors[fileName] = {
                path: f.filePath,
                errors: []
            };
        }

        errors.forEach(e => {
            fileErrors[fileName].errors.push({
                line: e.line,
                rule: e.ruleId,
                message: e.message
            });
        });
    }
});

// Sort files by error count
const sorted = Object.entries(fileErrors).sort((a, b) => b[1].errors.length - a[1].errors.length);

console.log('Files with errors (sorted by count):\n');
sorted.forEach(([file, data]) => {
    console.log(`\n${file} (${data.errors.length} errors):`);
    const errorsByRule = {};
    data.errors.forEach(e => {
        if (!errorsByRule[e.rule]) errorsByRule[e.rule] = [];
        errorsByRule[e.rule].push(e.line);
    });
    Object.entries(errorsByRule).forEach(([rule, lines]) => {
        console.log(`  ${rule}: lines ${lines.join(', ')}`);
    });
});

const fs = require('fs');
const data = JSON.parse(fs.readFileSync('productos_lint.json', 'utf8'));

const file = data[0];
const errors = file.messages.filter(m => m.severity === 2);

console.log(`Total errors: ${errors.length}\n`);

// Group by rule
const byRule = {};
errors.forEach(e => {
    if (!byRule[e.ruleId]) byRule[e.ruleId] = [];
    byRule[e.ruleId].push(e);
});

Object.entries(byRule).forEach(([rule, errs]) => {
    console.log(`\n${rule} (${errs.length} occurrences):`);
    errs.slice(0, 5).forEach(e => {
        console.log(`  Line ${e.line}: ${e.message.substring(0, 80)}`);
    });
    if (errs.length > 5) {
        console.log(`  ... and ${errs.length - 5} more`);
    }
});

import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

async function main() {
    console.log('🔍 Checking database connection...')
    try {
        // Attempt to raw query table names
        const result = await prisma.$queryRaw`
      SELECT table_name 
      FROM information_schema.tables 
      WHERE table_schema = 'public'
    `
        console.log('✅ Connected successfully.')
        console.log('Tables found:', result)

        // Try to count users
        try {
            const userCount = await prisma.user.count();
            console.log(`✅ User table accessible. Count: ${userCount}`);
        } catch (e: any) {
            console.error('❌ Failed to query User table:', e.message);
        }

    } catch (e) {
        console.error('❌ Database connection failed:', e)
    } finally {
        await prisma.$disconnect()
    }
}

