                            </div>
                        </div>
                    </div>

                    {/* Recipe Builder */}
                    <div className="bg-white p-8 rounded-[2rem] border border-zinc-200 shadow-sm space-y-6">
                        <div className="flex items-center justify-between">
                            <Label className="text-sm font-bold uppercase tracking-widest text-zinc-400">Receta (Insumos)</Label>
                            <Badge variant="outline" className="rounded-full border-zinc-200 text-zinc-500">
                                {recipeItems.length} Insumos
                            </Badge>
                        </div>

                        {/* Supply Search & Grid */}
                        <div className="space-y-4">
                            <div className="relative group">
                                <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-zinc-400 group-focus-within:text-zinc-600 transition-colors" />
                                <Input
                                    placeholder="Buscar insumos para añadir a la receta..."
                                    className="pl-11 h-12 bg-zinc-50 border-zinc-200 rounded-2xl focus-visible:ring-zinc-400"
                                    value={searchSupply}
                                    onChange={(e) => setSearchSupply(e.target.value)}
                                />

                                {searchSupply && filteredSupplies.length > 0 && (
                                    <div className="absolute z-10 w-full mt-2 bg-white rounded-2xl border border-zinc-200 shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                                        {filteredSupplies.map(supply => (
                                            <button
                                                key={supply.id}
                                                type="button"
                                                className="w-full text-left px-5 py-3 hover:bg-zinc-50 flex items-center justify-between group transition-colors"
                                                onClick={() => {
                                                    addRecipeItem(supply);
                                                    setSearchSupply("");
                                                }}
                                            >
                                                <div className="flex flex-col">
                                                    <span className="font-semibold text-zinc-900 text-sm">{supply.nombre}</span>
                                                    <span className="text-[0.65rem] text-zinc-400 uppercase font-bold tracking-tighter">{supply.unidad} • ${Number(supply.costoUnitario).toFixed(2)} p/unidad</span>
                                                </div>
                                                <Plus className="h-4 w-4 text-zinc-300 group-hover:text-zinc-900 transition-colors" />
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Quick Select Grid */}
                            <div className="space-y-3">
                                <div className="flex items-center justify-between px-1">
                                    <Label className="text-[10px] font-bold uppercase tracking-widest text-zinc-400">Selección Rápida</Label>
                                    {searchSupply && (
                                        <Button
                                            variant="ghost"
                                            size="sm"
                                            className="h-6 px-2 text-[10px] text-zinc-400 hover:text-zinc-900"
                                            onClick={() => setSearchSupply("")}
                                        >
                                            Limpiar búsqueda
                                        </Button>
                                    )}
                                </div>
                                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-2">
                                    {filteredSupplies.length > 0 ? (
                                        filteredSupplies.slice(0, 12).map(supply => (
                                            <button
                                                key={supply.id}
                                                type="button"
                                                onClick={() => addRecipeItem(supply)}
                                                className="flex flex-col items-start gap-1 p-3 bg-zinc-50 border border-zinc-100 rounded-2xl hover:bg-white hover:border-zinc-300 hover:shadow-sm transition-all text-left group"
                                            >
                                                <span className="text-xs font-semibold text-zinc-700 truncate w-full group-hover:text-zinc-900">{supply.nombre}</span>
                                                <span className="text-[9px] font-bold text-zinc-400 uppercase tracking-tighter">{supply.unidad}</span>
                                            </button>
                                        ))
                                    ) : (
                                        <div className="col-span-full py-4 text-center bg-zinc-50/50 rounded-2xl border border-dashed border-zinc-200">
                                            <p className="text-[10px] font-medium text-zinc-400">No hay insumos disponibles{searchSupply && " para esta búsqueda"}.</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>

                        {/* Recipe List */}
                        <div className="space-y-3">
                            {recipeItems.map(item => (
                                <div
                                    key={item.supplyId}
                                    className="flex items-center gap-4 bg-zinc-50/50 p-4 rounded-2xl border border-zinc-100 group hover:bg-zinc-50 transition-colors"
                                >
                                    <div className="flex-grow">
                                        <p className="font-semibold text-zinc-900 text-sm">{item.supplyName}</p>
                                        <p className="text-[0.65rem] text-zinc-400 font-bold uppercase tracking-tighter">Por UNIDAD</p>
                                    </div>
                                    <div className="flex items-center gap-3">
                                        <Input
                                            type="number"
                                            step="any"
                                            className="w-20 h-10 bg-white border-zinc-200 rounded-xl text-center font-bold text-zinc-900"
                                            value={item.qtyPerUnit || ""}
                                            onChange={(e) => updateRecipeItemQty(item.supplyId, e.target.value)}
                                        />
                                        <span className="text-xs font-bold text-zinc-400 min-w-[50px]">{item.unidad}</span>
                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            className="h-9 w-9 rounded-xl text-zinc-400 hover:text-red-500 hover:bg-red-50"
                                            onClick={() => removeRecipeItem(item.supplyId)}
                                        >
                                            <Trash2 className="h-4 w-4" />
                                        </Button>
                                    </div>
                                </div>
                            ))}

                            {recipeItems.length === 0 && (
                                <div className="text-center py-12 bg-zinc-50/30 rounded-[2rem] border border-dashed border-zinc-200">
                                    <p className="text-sm text-zinc-400">No hay insumos en la receta aún.</p>
                                    <p className="text-[0.7rem] text-zinc-300">Usa el buscador arriba para añadir ingredientes.</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useMemo, useEffect, useCallback } from "react";
import { Search, Plus, Filter, X, ChevronUp, ChevronDown, MoreVertical, Image as ImageIcon, Loader2, ListTree, Trash2 } from "lucide-react";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger, DropdownMenuCheckboxItem, DropdownMenuSeparator, DropdownMenuLabel } from "@/components/ui/dropdown-menu";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from "@/components/ui/sheet";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { getProducts, getCategories, toggleProductAvailability, softDeleteProduct, createProduct, updateProduct, createPromotion, deletePromotion } from "./actions";
import { Prisma } from "@prisma/client";
import { toast } from "sonner";

// Unified Menu Item type
interface MenuItem {
    id: string;
    type: 'PRODUCTO' | 'PROMOCION';
    nombre: string;
    descripcion: string | null;
    precio: number;
    imagen: string | null;
    categoria: string;
    categoryId: string;
    activo: boolean;
    disponible: boolean;
    unidad: string;
    createdAt: Date;
    updatedAt?: Date;
    deletedAt?: Date | null;
    costoUnitario?: number;
    // Original Prisma objects for actions if needed
    category?: Category;
};

type Category = Prisma.CategoryGetPayload<{ select: { id: true; nombre: true } }>;


// Mock products with all fields

type SortField = "codigo" | "nombre" | "categoria" | "precio" | "costo" | "margen" | "unidad" | "fecha" | "estado";
type SortDirection = "asc" | "desc";

interface MetricCardProps {
    title: string;
    value: string | number;
    change?: string;
    trend?: "up" | "down";
    headerColor: string;
    icon?: React.ReactNode;
}

function MetricCard({ title, value, change, headerColor, icon }: MetricCardProps) {
    return (
        <div className="bg-white rounded-[2rem] border border-zinc-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-md transition-shadow duration-300">
            {/* Colored Header Strip */}
            <div className={`h-12 ${headerColor} flex items-center px-6 text-white font-medium text-sm`}>
                {title}
                {icon && <div className="ml-auto opacity-80">{icon}</div>}
            </div>
            {/* Body */}
            <div className="p-6 flex flex-col justify-between flex-grow">
                <div className="flex items-end gap-3">
                    <span className="text-3xl font-bold text-zinc-900 tracking-tight">{value}</span>
                    {change && (
                        <span className="mb-1 bg-zinc-100 text-zinc-600 px-3 py-1 rounded-full text-[0.65rem] font-bold uppercase tracking-wider">
                            {change}
                        </span>
                    )}
                </div>
            </div>
        </div>
    );
}

export default function ProductosPage() {
    const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
    const [categories, setCategories] = useState<Category[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    const refreshData = useCallback(async () => {
        setIsLoading(true);
        try {
            const [menuRes, catRes] = await Promise.all([
                fetch('/api/admin/dashboard/productos').then(res => res.json()),
                fetch('/api/admin/dashboard/productos/categorias').then(res => res.json())
            ]);

            if (menuRes.success) {
                setMenuItems(menuRes.data);
            } else {
                toast.error(menuRes.error || "Error al cargar el menú");
            }

            if (catRes.success && catRes.data) {
                setCategories(catRes.data as Category[]);
            } else {
                toast.error(catRes.error || "Error al cargar categorías");
            }
        } catch (error) {
            console.error("Error refreshing data:", error);
            toast.error("Error de conexión");
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        refreshData();
    }, [refreshData]);

    const handleToggleAvailability = async (id: string, currentStatus: boolean) => {
        const res = await toggleProductAvailability(id, currentStatus);
        if (res.success) {
            toast.success("Disponibilidad actualizada");
            refreshData();
        } else {
            toast.error(res.error || "Error al actualizar");
        }
    };

    const [isSubmitting, setIsSubmitting] = useState(false);


    type ProductWithCategory = Prisma.ProductGetPayload<{
        include: { category: true }
    }>;

    const handleDuplicate = async (product: MenuItem) => {
        setIsSubmitting(true);
        const { id, createdAt, updatedAt, deletedAt, category, ...rest } = product;
        const res = await createProduct({
            ...rest,
            descripcion: rest.descripcion ?? undefined,
            nombre: `${rest.nombre} (Copia)`,
        });
        if (res.success) {
            toast.success("Producto duplicado");
            refreshData();
        } else {
            toast.error(res.error || "Error al duplicar");
        }
        setIsSubmitting(false);
    };

    const handleDelete = async (item: MenuItem) => {
        if (!confirm(`¿Estás seguro de eliminar esta ${item.type.toLowerCase()}?`)) return;

        // In the future, we might need a separate deletePromotion action
        // For now, if it's a product, use softDeleteProduct
        if (item.type === 'PRODUCTO') {
            const res = await softDeleteProduct(item.id);
            if (res.success) {
                toast.success("Producto eliminado");
                refreshData();
            } else {
                toast.error(res.error || "Error al eliminar");
            }
        } else {
            const res = await deletePromotion(item.id);
            if (res.success) {
                toast.success("Promoción eliminada");
                refreshData();
            } else {
                toast.error(res.error || "Error al eliminar");
            }
        }
    };

    // Metrics calculations using real data
    const totalProducts = menuItems.filter(item => item.type === 'PRODUCTO').length;
    const activeProducts = menuItems.filter(item => item.type === 'PRODUCTO' && item.activo).length;
    const categoriesCount = categories.length;
    const outOfStockCount = menuItems.filter((item) => item.type === 'PRODUCTO' && !item.disponible).length;

    const [searchQuery, setSearchQuery] = useState("");
    const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
    const [statusFilter, setStatusFilter] = useState<"todos" | "activos" | "disponibles" | "agotados">("todos");
    const [sortField, setSortField] = useState<SortField>("nombre");
    const [sortDirection, setSortDirection] = useState<SortDirection>("asc");

    // Filter & sort logic
    const filteredAndSortedItems = useMemo(() => {
        const filtered = menuItems.filter((item) => {
            const matchesSearch =
                searchQuery === "" ||
                item.nombre.toLowerCase().includes(searchQuery.toLowerCase()) ||
                item.descripcion?.toLowerCase().includes(searchQuery.toLowerCase()) ||
                item.categoria.toLowerCase().includes(searchQuery.toLowerCase());

            const matchesCategory =
                selectedCategories.length === 0 || selectedCategories.includes(item.categoryId);

            const matchesStatus =
                statusFilter === "todos" ||
                (statusFilter === "activos" && item.activo) ||
                (statusFilter === "disponibles" && item.disponible) ||
                (statusFilter === "agotados" && !item.disponible);

            return matchesSearch && matchesCategory && matchesStatus;
        });

        // Sorting
        filtered.sort((a, b) => {
            let compareValue = 0;

            switch (sortField) {
                case "codigo":
                    compareValue = a.id.localeCompare(b.id);
                    break;
                case "nombre":
                    compareValue = a.nombre.localeCompare(b.nombre);
                    break;
                case "categoria":
                    compareValue = a.categoria.localeCompare(b.categoria);
                    break;
                case "precio":
                    compareValue = Number(a.precio) - Number(b.precio);
                    break;
                case "costo":
                    // Promotions might not have cost, use 0
                    const costoA = a.costoUnitario || 0;
                    const costoB = b.costoUnitario || 0;
                    compareValue = Number(costoA) - Number(costoB);
                    break;
                case "margen": {
                    const costoA = a.costoUnitario || 0;
                    const costoB = b.costoUnitario || 0;
                    const marginA = costoA
                        ? ((Number(a.precio) - Number(costoA)) / Number(a.precio)) * 100
                        : 0;
                    const marginB = costoB
                        ? ((Number(b.precio) - Number(costoB)) / Number(b.precio)) * 100
                        : 0;
                    compareValue = marginA - marginB;
                    break;
                }
                case "unidad":
                    compareValue = a.unidad.localeCompare(b.unidad);
                    break;
                case "fecha":
                    compareValue = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
                    break;
                case "estado":
                    compareValue = (a.activo ? 1 : 0) - (b.activo ? 1 : 0);
                    break;
            }

            return sortDirection === "asc" ? compareValue : -compareValue;
        });

        return filtered;
    }, [menuItems, searchQuery, selectedCategories, statusFilter, sortField, sortDirection]);

    const handleSort = (field: SortField) => {
        if (sortField === field) {
            setSortDirection(sortDirection === "asc" ? "desc" : "asc");
        } else {
            setSortField(field);
            setSortDirection("asc");
        }
    };



    const removeCategoryFilter = (cat: string) => {
        setSelectedCategories(prev => prev.filter(c => c !== cat));
    };

    const formatDate = (date: Date) => {
        const day = String(date.getDate()).padStart(2, "0");
        const month = String(date.getMonth() + 1).padStart(2, "0");
        const year = date.getFullYear();
        return `${day}.${month}.${year}`;
    };

    const calculateMargin = (precio: number, costo?: number) => {
        if (!costo) return 0;
        return ((precio - costo) / precio) * 100;
    };

    const truncateId = (id: string) => {
        return id.length > 12 ? `${id.slice(0, 12)}...` : id;
    };

    const SortIcon = ({ field }: { field: SortField }) => {
        if (sortField !== field) return null;
        return sortDirection === "asc" ? (
            <ChevronUp className="h-3 w-3 inline ml-1" />
        ) : (
            <ChevronDown className="h-3 w-3 inline ml-1" />
        );
    };

    const hasActiveFilters = searchQuery !== "" || selectedCategories.length > 0 || statusFilter !== "todos";

    return (
        <div className="flex flex-col gap-8 p-8 bg-zinc-50 min-h-screen">
            <div className="flex justify-between items-end">
                <div>
                    <h1 className="text-2xl font-bold text-zinc-900 tracking-tight">Catálogo de Productos</h1>
                    <p className="text-zinc-500 mt-1">Gestiona el inventario y precios de tu trattoria.</p>
                </div>
            </div>

            {/* Metrics Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                <MetricCard
                    title="Total productos"
                    value={totalProducts}
                    change="+12%"
                    headerColor="bg-blue-600"
                />
                <MetricCard
                    title="Productos activos"
                    value={activeProducts}
                    change="+5%"
                    headerColor="bg-orange-500"
                />
                <MetricCard
                    title="Categorías"
                    value={categoriesCount}
                    headerColor="bg-amber-400"
                />
                <MetricCard
                    title="Sin stock / Alertas"
                    value={outOfStockCount}
                    change="Revisar"
                    headerColor="bg-emerald-500"
                />
            </div>

            {/* Search and Filters */}
            <div className="flex flex-col gap-4 bg-white p-5 rounded-[2rem] border border-zinc-200 shadow-sm">
                <div className="flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">
                    <div className="relative w-full md:w-96 group">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-zinc-400 group-focus-within:text-zinc-600 transition-colors" />
                        <Input
                            placeholder="Buscar por nombre o código..."
                            className="pl-11 h-12 bg-zinc-50 border-zinc-200 rounded-full focus-visible:ring-zinc-400 transition-all text-sm"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>

                    <div className="flex flex-wrap items-center gap-3 w-full md:w-auto">
                        <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                                <Button variant="outline" className="h-12 rounded-full px-6 border-zinc-200 hover:bg-zinc-50 text-zinc-600 font-medium">
                                    <Filter className="mr-2 h-4 w-4" />
                                    Categorías
                                    {selectedCategories.length > 0 && (
                                        <Badge variant="secondary" className="ml-2 bg-zinc-100 text-zinc-900 font-bold px-2 py-0">
                                            {selectedCategories.length}
                                        </Badge>
                                    )}
                                </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end" className="w-56 rounded-2xl p-2 shadow-xl border-zinc-100">
                                <DropdownMenuLabel className="px-3 pb-2 text-[0.65rem] font-bold uppercase tracking-widest text-zinc-400">Seleccionar Categorías</DropdownMenuLabel>
                                {categories.map((cat) => (
                                    <DropdownMenuCheckboxItem
                                        key={cat.id}
                                        className="rounded-xl focus:bg-zinc-50 my-0.5"
                                        checked={selectedCategories.includes(cat.id)}
                                        onCheckedChange={(checked) => {
                                            if (checked) {
                                                setSelectedCategories([...selectedCategories, cat.id]);
                                            } else {
                                                setSelectedCategories(selectedCategories.filter((c) => c !== cat.id));
                                            }
                                        }}
                                    >
                                        {cat.nombre}
                                    </DropdownMenuCheckboxItem>
                                ))}
                            </DropdownMenuContent>
                        </DropdownMenu>

                        <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                                <Button variant="outline" className="h-12 rounded-full px-6 border-zinc-200 hover:bg-zinc-50 text-zinc-600 font-medium capitalize">
                                    {statusFilter === "todos" ? "Todos los estados" : statusFilter}
                                    <ChevronDown className="ml-2 h-4 w-4 opacity-50" />
                                </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end" className="w-56 rounded-2xl p-2 shadow-xl border-zinc-100">
                                <DropdownMenuItem className="rounded-xl my-0.5" onClick={() => setStatusFilter("todos")}>Todos los estados</DropdownMenuItem>
                                <DropdownMenuItem className="rounded-xl my-0.5" onClick={() => setStatusFilter("activos")}>Solo activos</DropdownMenuItem>
                                <DropdownMenuItem className="rounded-xl my-0.5" onClick={() => setStatusFilter("disponibles")}>Solo disponibles</DropdownMenuItem>
                                <DropdownMenuItem className="rounded-xl my-0.5" onClick={() => setStatusFilter("agotados")}>Agotados</DropdownMenuItem>
                            </DropdownMenuContent>
                        </DropdownMenu>

                        <div className="h-8 w-[1px] bg-zinc-200 mx-1 hidden md:block"></div>

                        <div className="flex items-center gap-3">
                            <Link href="/admin/dashboard/productos/categorias">
                                <Button variant="outline" className="rounded-full border-zinc-200 hover:bg-zinc-50 transition-all font-medium text-xs h-9 px-4">
                                    <ListTree className="h-3.5 w-3.5 mr-2" />
                                    Ver Categorías
                                </Button>
                            </Link>

                            <Link href="/admin/dashboard/productos/promociones/nueva">
                                <Button className="rounded-full bg-zinc-900 text-white hover:bg-zinc-800 transition-all font-medium text-xs h-9 px-4">
                                    <Plus className="h-3.5 w-3.5 mr-2" />
                                    Nueva Promoción
                                </Button>
                            </Link>

                            <Link href="/admin/dashboard/productos/nuevo">
                                <Button className="rounded-full bg-zinc-900 text-white hover:bg-zinc-800 shadow-sm transition-all font-medium text-xs h-9 px-4">
                                    <Plus className="h-4 w-4 mr-2" />
                                    Nuevo Producto
                                </Button>
                            </Link>
                        </div>
                    </div>
                </div>

                {/* Active Filters Pill Badges Row */}
                {hasActiveFilters && (
                    <>
                        <div className="h-[1px] bg-zinc-100 w-full my-1"></div>
                        <div className="flex flex-wrap items-center gap-2 px-1 py-1 animate-in fade-in slide-in-from-top-2 duration-300">
                            <span className="text-[0.65rem] font-bold text-zinc-400 uppercase tracking-widest mr-2">Filtros activos:</span>
                            {searchQuery && (
                                <Badge variant="secondary" className="bg-white border-zinc-200 text-zinc-600 pl-3 pr-1 py-1 h-8 rounded-full gap-1 shadow-sm font-medium">
                                    Búsqueda: {searchQuery}
                                    <Button variant="ghost" size="icon" className="h-6 w-6 rounded-full hover:bg-zinc-100" onClick={() => setSearchQuery("")}>
                                        <X className="h-3 w-3" />
                                    </Button>
                                </Badge>
                            )}
                            {selectedCategories.map(catId => {
                                const catName = categories.find(c => c.id === catId)?.nombre || catId;
                                return (
                                    <Badge key={catId} variant="secondary" className="bg-white border-zinc-200 text-zinc-600 pl-3 pr-1 py-1 h-8 rounded-full gap-1 shadow-sm font-medium">
                                        {catName}
                                        <Button variant="ghost" size="icon" className="h-6 w-6 rounded-full hover:bg-zinc-100" onClick={() => removeCategoryFilter(catId)}>
                                            <X className="h-3 w-3" />
                                        </Button>
                                    </Badge>
                                );
                            })}
                            {statusFilter !== "todos" && (
                                <Badge variant="secondary" className="bg-white border-zinc-200 text-zinc-600 pl-3 pr-1 py-1 h-8 rounded-full gap-1 shadow-sm font-medium">
                                    Estado: {statusFilter}
                                    <Button variant="ghost" size="icon" className="h-6 w-6 rounded-full hover:bg-zinc-100" onClick={() => setStatusFilter("todos")}>
                                        <X className="h-3 w-3" />
                                    </Button>
                                </Badge>
                            )}
                            <Button
                                variant="ghost"
                                size="sm"
                                className="text-xs text-zinc-400 hover:text-zinc-600 h-8 rounded-full px-3 hover:bg-transparent ml-auto"
                                onClick={() => {
                                    setSearchQuery("");
                                    setSelectedCategories([]);
                                    setStatusFilter("todos");
                                }}
                            >
                                Limpiar todos
                            </Button>
                        </div>
                    </>
                )}
            </div>

            {/* Products Table Container */}
            <div className="bg-white rounded-[2rem] border border-zinc-200 shadow-sm overflow-hidden mb-12">
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-zinc-50/50 border-b border-zinc-100">
                            <tr>
                                <th className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500">
                                    Tipo
                                </th>
                                <th onClick={() => handleSort("nombre")} className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500 cursor-pointer hover:text-zinc-700 transition-colors">
                                    Nombre <SortIcon field="nombre" />
                                </th>
                                <th className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500">
                                    Imagen
                                </th>
                                <th onClick={() => handleSort("categoria")} className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500 cursor-pointer hover:text-zinc-700 transition-colors">
                                    Categoría <SortIcon field="categoria" />
                                </th>
                                <th onClick={() => handleSort("precio")} className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500 cursor-pointer hover:text-zinc-700 transition-colors">
                                    Precio <SortIcon field="precio" />
                                </th>
                                <th onClick={() => handleSort("costo")} className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500 cursor-pointer hover:text-zinc-700 transition-colors">
                                    Costo <SortIcon field="costo" />
                                </th>
                                <th onClick={() => handleSort("margen")} className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500 cursor-pointer hover:text-zinc-700 transition-colors">
                                    Margen <SortIcon field="margen" />
                                </th>
                                <th onClick={() => handleSort("unidad")} className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500 cursor-pointer hover:text-zinc-700 transition-colors">
                                    Unidad <SortIcon field="unidad" />
                                </th>
                                <th onClick={() => handleSort("fecha")} className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500 cursor-pointer hover:text-zinc-700 transition-colors">
                                    Fecha <SortIcon field="fecha" />
                                </th>
                                <th onClick={() => handleSort("estado")} className="text-left px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500 cursor-pointer hover:text-zinc-700 transition-colors">
                                    Estado <SortIcon field="estado" />
                                </th>
                                <th className="text-right px-6 py-5 font-semibold text-[0.65rem] uppercase tracking-widest text-zinc-500">
                                    Acciones
                                </th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-zinc-100">
                            {filteredAndSortedItems.length === 0 ? (
                                <tr>
                                    <td colSpan={11} className="text-center py-20">
                                        <div className="flex flex-col items-center gap-3">
                                            <div className="h-16 w-16 bg-zinc-50 rounded-full flex items-center justify-center">
                                                <Search className="h-8 w-8 text-zinc-300" />
                                            </div>
                                            <p className="text-zinc-500 font-medium">No se encontraron elementos</p>
                                            <p className="text-xs text-zinc-400">Intenta ajustando los filtros de búsqueda</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : (
                                filteredAndSortedItems.map(item => (
                                    <tr
                                        key={item.id}
                                        className="group border-b border-zinc-100 hover:bg-zinc-50/50 transition-all duration-150"
                                    >
                                        <td className="px-6 py-4">
                                            <Badge
                                                variant="secondary"
                                                className={
                                                    item.type === 'PRODUCTO'
                                                        ? "bg-blue-50 text-blue-600 border-none font-bold text-[0.6rem] px-2 py-0.5 rounded-full"
                                                        : "bg-purple-50 text-purple-600 border-none font-bold text-[0.6rem] px-2 py-0.5 rounded-full"
                                                }
                                            >
                                                {item.type}
                                            </Badge>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col">
                                                <span className="font-semibold text-zinc-900 text-sm">{item.nombre}</span>
                                                {item.descripcion && (
                                                    <span className="text-[0.7rem] text-zinc-400 line-clamp-1 mt-0.5">{item.descripcion}</span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            {item.imagen ? (
                                                <div className="h-12 w-12 rounded-2xl overflow-hidden border border-zinc-100 shadow-sm">
                                                    <img
                                                        src={item.imagen}
                                                        alt={item.nombre}
                                                        className="h-full w-full object-cover group-hover:scale-110 transition-transform duration-300"
                                                    />
                                                </div>
                                            ) : (
                                                <div className="h-12 w-12 rounded-2xl bg-zinc-50 flex items-center justify-center border border-zinc-100">
                                                    <ImageIcon className="h-5 w-5 text-zinc-300" />
                                                </div>
                                            )}
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-xs font-medium text-zinc-500">
                                            {item.categoria}
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="font-bold text-zinc-900 text-sm">${Number(item.precio).toFixed(2)}</span>
                                        </td>
                                        <td className="px-6 py-4">
                                            {item.costoUnitario ? (
                                                <span className="text-xs text-zinc-400">${Number(item.costoUnitario).toFixed(2)}</span>
                                            ) : (
                                                <span className="text-xs text-zinc-300">-</span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4">
                                            {item.costoUnitario ? (
                                                <span className="text-xs font-bold text-zinc-500 bg-zinc-50 px-2 py-1 rounded-md">
                                                    {calculateMargin(Number(item.precio), Number(item.costoUnitario)).toFixed(1)}%
                                                </span>
                                            ) : (
                                                <span className="text-xs text-zinc-300">-</span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4">
                                            <Badge variant="outline" className="border-zinc-200 text-zinc-500 font-medium text-[0.6rem] uppercase tracking-tighter px-2 py-0">
                                                {item.unidad}
                                            </Badge>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <span className="text-xs text-zinc-500 font-medium">{formatDate(new Date(item.createdAt))}</span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-wrap gap-2">
                                                <Badge
                                                    variant="secondary"
                                                    className={
                                                        item.activo
                                                            ? "bg-emerald-50 text-emerald-600 border-none font-bold text-[0.6rem] px-2 py-0.5 rounded-full"
                                                            : "bg-red-50 text-red-600 border-none font-bold text-[0.6rem] px-2 py-0.5 rounded-full"
                                                    }
                                                >
                                                    {item.activo ? "ACTIVO" : "INACTIVO"}
                                                </Badge>
                                                {item.type === 'PRODUCTO' && !item.disponible && (
                                                    <Badge variant="secondary" className="bg-orange-50 text-orange-600 border-none font-bold text-[0.6rem] px-2 py-0.5 rounded-full">
                                                        AGOTADO
                                                    </Badge>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <DropdownMenu>
                                                <DropdownMenuTrigger asChild>
                                                    <Button variant="ghost" size="sm" className="h-8 w-8 p-0 rounded-full hover:bg-zinc-100">
                                                        <MoreVertical className="h-4 w-4 text-zinc-400" />
                                                    </Button>
                                                </DropdownMenuTrigger>
                                                <DropdownMenuContent align="end" className="w-48 rounded-2xl p-2 shadow-xl border-zinc-100">
                                                    <DropdownMenuItem className="rounded-xl my-0.5">
                                                        <Link
                                                            href={item.type === 'PRODUCTO'
                                                                ? `/admin/dashboard/productos/${item.id}`
                                                                : `/admin/dashboard/productos/promociones/${item.id}`
                                                            }
                                                            className="w-full"
                                                        >
                                                            Ver detalles
                                                        </Link>
                                                    </DropdownMenuItem>
                                                    <DropdownMenuItem className="rounded-xl my-0.5">
                                                        <Link
                                                            href={item.type === 'PRODUCTO'
                                                                ? `/admin/dashboard/productos/${item.id}/editar`
                                                                : `/admin/dashboard/productos/promociones/${item.id}/editar`
                                                            }
                                                            className="w-full"
                                                        >
                                                            Editar
                                                        </Link>
                                                    </DropdownMenuItem>
                                                    {item.type === 'PRODUCTO' && (
                                                        <DropdownMenuItem className="rounded-xl my-0.5" onClick={() => handleDuplicate(item)}>Duplicar</DropdownMenuItem>
                                                    )}
                                                    <DropdownMenuSeparator className="bg-zinc-50" />
                                                    {item.type === 'PRODUCTO' && (
                                                        <DropdownMenuItem
                                                            className="rounded-xl my-0.5"
                                                            onClick={async () => {
                                                                setIsSubmitting(true);
                                                                const res = await toggleProductAvailability(item.id, item.disponible);
                                                                if (res.success) {
                                                                    toast.success(item.disponible ? "Producto marcado como agotado" : "Producto marcado como disponible");
                                                                    refreshData();
                                                                } else {
                                                                    toast.error(res.error || "Error al actualizar");
                                                                }
                                                                setIsSubmitting(false);
                                                            }}
                                                        >
                                                            {item.disponible ? "Marcar como agotado" : "Marcar como disponible"}
                                                        </DropdownMenuItem>
                                                    )}
                                                    <DropdownMenuItem
                                                        className="rounded-xl my-0.5 text-red-600 hover:bg-red-50 focus:bg-red-50 focus:text-red-700"
                                                        onClick={() => handleDelete(item)}
                                                    >
                                                        Eliminar
                                                    </DropdownMenuItem>
                                                </DropdownMenuContent>
                                            </DropdownMenu>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback, useMemo, useRef, use } from "react";
import { useRouter } from "next/navigation";
import {
    ChevronLeft,
    Save,
    Tag,
    Calendar,
    Image as ImageIcon,
    LayoutGrid,
    Package,
    Plus,
    X,
    Check,
    Search,
    Loader2,
    AlertCircle,
    Info,
    Clock,
    DollarSign,
    Percent,
    Upload,
    Minus,
    Trash2
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { getCategories, getProducts, updatePromotion, getPromotionById, deletePromotion } from "../../../actions";
import Link from "next/link";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from "@/components/ui/alert-dialog";

interface SelectionItem {
    id: string;
    nombre: string;
    precio: number;
    imagen?: string | null;
    categoryId: string;
}

interface SelectedProduct {
    id: string;
    quantity: number;
}

const DAYS = [
    { label: "Lun", value: "L" },
    { label: "Mar", value: "M" },
    { label: "Mié", value: "X" },
    { label: "Jue", value: "J" },
    { label: "Vie", value: "V" },
    { label: "Sáb", value: "S" },
    { label: "Dom", value: "D" },
];

export default function EditarPromocionPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const router = useRouter();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [loading, setLoading] = useState(false);
    const [fetchingData, setFetchingData] = useState(true);
    const [isDeleting, setIsDeleting] = useState(false);

    const [categories, setCategories] = useState<any[]>([]);
    const [products, setProducts] = useState<SelectionItem[]>([]);

    const [formData, setFormData] = useState({
        name: "",
        description: "",
        code: "",
        finalPrice: "",
        startDate: "",
        endDate: "",
        imagen: "",
        isActive: true,
    });

    const [selectedProducts, setSelectedProducts] = useState<SelectedProduct[]>([]);
    const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
    const [selectedDays, setSelectedDays] = useState<string[]>([]);

    const [productSearch, setProductSearch] = useState("");
    const [previewImage, setPreviewImage] = useState<string | null>(null);

    const fetchData = useCallback(async () => {
        try {
            setFetchingData(true);
            const [catRes, prodRes] = await Promise.all([
                getCategories(),
                getProducts(),
            ]);
            const promoRes = await getPromotionById(id);

            if (catRes.success) {
                const promoCats = catRes.data.filter((c: any) =>
                    c.nombre.toLowerCase().includes("promo")
                );
                setCategories(promoCats.length > 0 ? promoCats : catRes.data);
            }

            if (prodRes.success) {
                setProducts(prodRes.data);
            }

            if (promoRes.success) {
                const promo = promoRes.data;

                // Calculate original total price to deduce the finalPrice from discountValue if needed
                // But usually we save the finalPrice or discountValue.
                // Based on NuevaPromocionPage, it saves discountValue = totalOriginal - finalPrice
                // So finalPrice = totalOriginal - discountValue

                const initialSelectedProducts = promo.items.map((item: any) => ({
                    id: item.productId,
                    quantity: item.quantity
                }));

                setSelectedProducts(initialSelectedProducts);

                // Calculate total original price of these items
                let totalOrig = 0;
                initialSelectedProducts.forEach((sp: any) => {
                    const product = (prodRes.data as SelectionItem[]).find(p => p.id === sp.id);
                    if (product) totalOrig += Number(product.precio) * sp.quantity;
                });

                setFormData({
                    name: promo.name || "",
                    description: promo.description || "",
                    code: promo.code || "",
                    finalPrice: (totalOrig - Number(promo.discountValue)).toString(),
                    startDate: promo.startDate ? new Date(promo.startDate).toISOString().split('T')[0] : "",
                    endDate: promo.endDate ? new Date(promo.endDate).toISOString().split('T')[0] : "",
                    imagen: promo.imagen || "",
                    isActive: promo.isActive,
                });

                if (promo.imagen) setPreviewImage(promo.imagen);
                if (promo.daysOfWeek) setSelectedDays(promo.daysOfWeek.split(","));
                if (promo.categories) setSelectedCategories(promo.categories.map((c: any) => c.id));
            } else {
                toast.error(promoRes.error || "No se pudo encontrar la promoción");
                router.push("/admin/dashboard/productos");
            }
        } catch (error) {
            console.error("Error fetching data:", error);
            toast.error("Error al cargar datos necesarios");
        } finally {
            setFetchingData(false);
        }
    }, [id, router]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const totalOriginalPrice = useMemo(() => {
        return selectedProducts.reduce((sum, sp) => {
            const product = products.find(p => p.id === sp.id);
            return sum + (product ? Number(product.precio) * sp.quantity : 0);
        }, 0);
    }, [selectedProducts, products]);

    const calculatedDiscount = useMemo(() => {
        const final = Number(formData.finalPrice) || 0;
        if (totalOriginalPrice === 0) return 0;
        return Math.max(0, totalOriginalPrice - final);
    }, [totalOriginalPrice, formData.finalPrice]);

    const savingsPercentage = useMemo(() => {
        if (totalOriginalPrice === 0 || calculatedDiscount === 0) return 0;
        return Math.round((calculatedDiscount / totalOriginalPrice) * 100);
    }, [totalOriginalPrice, calculatedDiscount]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name) {
            toast.error("El nombre de la promoción es obligatorio");
            return;
        }

        if (selectedProducts.length === 0) {
            toast.error("Debes seleccionar al menos un producto");
            return;
        }

        setLoading(true);
        try {
            const res = await updatePromotion(id, {
                ...formData,
                discountType: "FIXED_AMOUNT",
                discountValue: calculatedDiscount,
                daysOfWeek: selectedDays.join(","),
                items: selectedProducts.map(p => ({ productId: p.id, quantity: p.quantity })),
                categoryIds: selectedCategories,
            });

            if (res.success) {
                toast.success("Promoción actualizada satisfactoriamente");
                router.push("/admin/dashboard/productos");
            } else {
                toast.error(res.error || "Error al actualizar la promoción");
            }
        } catch (error) {
            toast.error("Error inesperado");
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async () => {
        setIsDeleting(true);
        try {
            const res = await deletePromotion(id);
            if (res.success) {
                toast.success("Promoción eliminada");
                router.push("/admin/dashboard/productos");
            } else {
                toast.error(res.error || "Error al eliminar");
            }
        } catch (error) {
            toast.error("Error de conexión");
        } finally {
            setIsDeleting(false);
        }
    };

    const toggleProduct = (id: string) => {
        setSelectedProducts(prev => {
            const existing = prev.find(p => p.id === id);
            if (existing) {
                return prev.filter(p => p.id !== id);
            } else {
                return [...prev, { id, quantity: 1 }];
            }
        });
    };

    const updateProductQuantity = (id: string, delta: number) => {
        setSelectedProducts(prev => prev.map(p => {
            if (p.id === id) {
                const newQty = Math.max(1, p.quantity + delta);
                return { ...p, quantity: newQty };
            }
            return p;
        }));
    };

    const toggleDay = (val: string) => {
        setSelectedDays(prev =>
            prev.includes(val) ? prev.filter(d => d !== val) : [...prev, val]
        );
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setPreviewImage(reader.result as string);
                setFormData({ ...formData, imagen: reader.result as string });
            };
            reader.readAsDataURL(file);
        }
    };

    if (fetchingData) {
        return (
            <div className="flex h-[80vh] items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-zinc-400" />
            </div>
        );
    }

    const filteredProducts = products.filter(p =>
        p.nombre.toLowerCase().includes(productSearch.toLowerCase())
    );

    return (
        <form onSubmit={handleSubmit} className="flex flex-col gap-8 p-12 bg-[#F8F9FA] min-h-screen w-full">
            {/* Header section - Full Width */}
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 sticky top-0 z-20 bg-[#F8F9FA]/90 backdrop-blur-xl py-6 -mt-12 border-b border-zinc-100">
                <div className="flex items-center gap-6">
                    <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        onClick={() => router.back()}
                        className="h-14 w-14 rounded-[1.5rem] bg-white shadow-sm border border-zinc-200 hover:border-zinc-900 transition-all hover:scale-105 active:scale-95"
                    >
                        <ChevronLeft className="h-7 w-7 text-zinc-900" />
                    </Button>
                    <div>
                        <h1 className="text-4xl font-black text-zinc-900 tracking-tight">Editar Promoción</h1>
                        <p className="text-zinc-500 text-lg font-medium opacity-70 italic">Perfecciona tu oferta para atraer más clientes</p>
                    </div>
                </div>

                <div className="flex items-center gap-4 w-full lg:w-auto">
                    <AlertDialog>
                        <AlertDialogTrigger asChild>
                            <Button
                                type="button"
                                variant="outline"
                                className="flex-1 lg:flex-none rounded-[2rem] border-red-100 text-red-500 hover:bg-red-50 hover:border-red-200 transition-all font-bold h-14 px-8 text-lg"
                            >
                                <Trash2 className="h-5 w-5 mr-2" />
                                Eliminar
                            </Button>
                        </AlertDialogTrigger>
                        <AlertDialogContent className="rounded-[2rem] p-8 border-none shadow-2xl">
                            <AlertDialogHeader>
                                <AlertDialogTitle className="text-2xl font-black text-zinc-900">¿Estás completamente seguro?</AlertDialogTitle>
                                <AlertDialogDescription className="text-zinc-500 font-medium text-lg">
                                    Esta acción no se puede deshacer. La promoción se marcará como eliminada y no aparecerá más en el catálogo.
                                </AlertDialogDescription>
                            </AlertDialogHeader>
                            <AlertDialogFooter className="mt-6 gap-3">
                                <AlertDialogCancel className="rounded-2xl h-12 px-6 font-bold border-zinc-200">Cancelar</AlertDialogCancel>
                                <AlertDialogAction
                                    onClick={handleDelete}
                                    className="rounded-2xl h-12 px-8 font-black bg-red-600 text-white hover:bg-red-700 shadow-lg shadow-red-200"
                                >
                                    Sí, eliminar promoción
                                </AlertDialogAction>
                            </AlertDialogFooter>
                        </AlertDialogContent>
                    </AlertDialog>

                    <Button
                        type="submit"
                        disabled={loading}
                        className="flex-1 lg:flex-none rounded-[2rem] bg-zinc-900 text-white hover:bg-zinc-800 transition-all font-black h-14 px-12 text-lg shadow-2xl shadow-zinc-300 transform motion-safe:hover:-translate-y-1 active:scale-95"
                    >
                        {loading ? <Loader2 className="h-6 w-6 animate-spin mr-3" /> : <Save className="h-6 w-6 mr-3" />}
                        Guardar Cambios
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                {/* Left Column - Configuration (Basic Info & Vigencia) */}
                <div className="xl:col-span-4 space-y-10">
                    {/* Basic Info */}
                    <Card className="rounded-[3rem] border-none shadow-[0_20px_50px_rgba(0,0,0,0.05)] overflow-hidden bg-white">
                        <CardHeader className="p-10 pb-0">
                            <Badge className="w-fit bg-zinc-900 text-white font-black px-4 py-1 rounded-full text-xs">CONFIGURACIÓN</Badge>
                            <h2 className="text-2xl font-black text-zinc-900">Información General</h2>
                        </CardHeader>
                        <CardContent className="p-10 space-y-8">
                            <div className="space-y-3">
                                <Label className="text-xs font-black text-zinc-400 uppercase tracking-[0.2em] ml-2">Nombre de la Promo</Label>
                                <Input
                                    placeholder="Ej: Mega Combo Familiar"
                                    className="h-16 rounded-[1.5rem] border-zinc-100 bg-zinc-50 font-bold text-xl px-6 focus:border-zinc-900 focus:ring-0"
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                                />
                            </div>

                            <div className="space-y-3">
                                <Label className="text-xs font-black text-zinc-400 uppercase tracking-[0.2em] ml-2">Descripción</Label>
                                <Textarea
                                    placeholder="Cuéntale a tus clientes qué incluye..."
                                    className="min-h-[120px] rounded-[2rem] border-zinc-100 bg-zinc-50 font-medium p-6 text-lg focus:border-zinc-900 focus:ring-0 italic"
                                    value={formData.description}
                                    onChange={e => setFormData({ ...formData, description: e.target.value })}
                                />
                            </div>

                            <div className="space-y-4">
                                <Label className="text-xs font-black text-zinc-400 uppercase tracking-[0.2em] ml-2">Imagen Publicitaria</Label>
                                <div
                                    onClick={() => fileInputRef.current?.click()}
                                    className="relative h-64 w-full rounded-[2.5rem] border-4 border-dashed border-zinc-100 hover:border-zinc-900 transition-all bg-zinc-50 flex flex-col items-center justify-center gap-4 cursor-pointer overflow-hidden group"
                                >
                                    {previewImage ? (
                                        <>
                                            <img src={previewImage} alt="Preview" className="h-full w-full object-cover" />
                                            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center transition-all">
                                                <Upload className="h-10 w-10 text-white" />
                                            </div>
                                        </>
                                    ) : (
                                        <>
                                            <div className="h-20 w-20 bg-white rounded-3xl shadow-lg flex items-center justify-center">
                                                <Upload className="h-10 w-10 text-zinc-400" />
                                            </div>
                                            <div className="text-center">
                                                <p className="font-black text-zinc-900">Seleccionar Archivo</p>
                                                <p className="text-xs text-zinc-400 font-bold uppercase tracking-widest mt-1">PNG, JPG hasta 5MB</p>
                                            </div>
                                        </>
                                    )}
                                    <input
                                        type="file"
                                        ref={fileInputRef}
                                        className="hidden"
                                        accept="image/*"
                                        onChange={handleFileChange}
                                    />
                                </div>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Vigencia & Días */}
                    <Card className="rounded-[3rem] border-none shadow-[0_20px_50px_rgba(0,0,0,0.05)] overflow-hidden bg-white">
                        <CardHeader className="p-10 pb-0">
                            <div className="flex flex-col gap-2">
                                <Badge className="w-fit bg-zinc-900 text-white font-black px-4 py-1 rounded-full text-xs">VIGENCIA</Badge>
                                <h2 className="text-2xl font-black text-zinc-900">¿Cuándo se activa?</h2>
                            </div>
                        </CardHeader>
                        <CardContent className="p-10 space-y-10">
                            <div className="grid grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <Label className="text-[0.65rem] font-black text-zinc-400 uppercase tracking-widest ml-1">Fecha Desde</Label>
                                    <Input
                                        type="date"
                                        className="h-14 rounded-[1.2rem] border-zinc-100 bg-zinc-50 font-bold px-4"
                                        value={formData.startDate}
                                        onChange={e => setFormData({ ...formData, startDate: e.target.value })}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-[0.65rem] font-black text-zinc-400 uppercase tracking-widest ml-1">Fecha Hasta</Label>
                                    <Input
                                        type="date"
                                        className="h-14 rounded-[1.2rem] border-zinc-100 bg-zinc-50 font-bold px-4 focus:ring-zinc-900"
                                        value={formData.endDate}
                                        onChange={e => setFormData({ ...formData, endDate: e.target.value })}
                                    />
                                </div>
                            </div>

                            <div className="space-y-4">
                                <Label className="text-[0.65rem] font-black text-zinc-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                                    <Clock className="h-3 w-3" />
                                    Días específicos
                                </Label>
                                <div className="flex flex-wrap gap-2">
                                    {DAYS.map(day => (
                                        <button
                                            key={day.value}
                                            type="button"
                                            onClick={() => toggleDay(day.value)}
                                            className={`h-11 w-11 rounded-xl font-black text-xs transition-all border-2 ${selectedDays.includes(day.value)
                                                ? 'bg-zinc-900 text-white border-zinc-900 shadow-xl shadow-zinc-200'
                                                : 'bg-white text-zinc-400 border-zinc-50 hover:border-zinc-200'
                                                }`}
                                        >
                                            {day.label}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Right Column - Product Grid Selection, Categories & Price */}
                <div className="xl:col-span-8 space-y-10">
                    <div className="flex justify-between items-end px-2">
                        <div>
                            <h2 className="text-4xl font-black text-zinc-900 tracking-tight">Selección de Productos</h2>
                            <p className="text-zinc-500 font-bold">Añade o retira productos de la promoción</p>
                        </div>
                        <div className="bg-white p-2 rounded-2xl border border-zinc-100 flex items-center gap-3 shadow-sm">
                            <Search className="h-5 w-5 text-zinc-400 ml-2" />
                            <Input
                                placeholder="Buscar platillo..."
                                className="border-none bg-transparent h-10 w-64 focus-visible:ring-0 font-bold"
                                value={productSearch}
                                onChange={e => setProductSearch(e.target.value)}
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 2xl:grid-cols-4 gap-6">
                        {filteredProducts.map(product => {
                            const selected = selectedProducts.find(p => p.id === product.id);
                            const isSelected = !!selected;

                            return (
                                <div
                                    key={product.id}
                                    className={`group relative rounded-[2.5rem] border-4 transition-all overflow-hidden bg-white flex flex-col ${isSelected
                                        ? 'border-zinc-900 ring-4 ring-zinc-100'
                                        : 'border-transparent shadow-sm hover:shadow-xl hover:border-zinc-100'
                                        }`}
                                >
                                    <div
                                        onClick={() => toggleProduct(product.id)}
                                        className="h-32 w-full bg-zinc-50 flex items-center justify-center overflow-hidden cursor-pointer relative"
                                    >
                                        {product.imagen ? (
                                            <img src={product.imagen} alt={product.nombre} className="h-full w-full object-cover group-hover:scale-105 transition-transform duration-500" />
                                        ) : (
                                            <ImageIcon className="h-10 w-10 text-zinc-200" />
                                        )}
                                        {isSelected && (
                                            <div className="absolute top-3 right-3 bg-zinc-900 text-white rounded-full p-1.5 shadow-xl">
                                                <Check className="h-3 w-3 stroke-[4px]" />
                                            </div>
                                        )}
                                    </div>

                                    <div className="p-5 flex-1 flex flex-col justify-between">
                                        <div>
                                            <h4 className="font-black text-lg text-zinc-900 leading-tight uppercase tracking-tighter mb-1 line-clamp-1">
                                                {product.nombre}
                                            </h4>
                                            <p className="text-zinc-400 text-[0.6rem] font-black uppercase tracking-widest leading-none mb-3">ID: {product.id.slice(-6)}</p>
                                            <span className="text-xl font-black text-zinc-900 tracking-tight">${Number(product.precio).toLocaleString()}</span>
                                        </div>

                                        {isSelected && (
                                            <div className="mt-4 flex items-center justify-between p-1 bg-zinc-100 rounded-2xl">
                                                <button
                                                    type="button"
                                                    onClick={(e) => { e.stopPropagation(); updateProductQuantity(product.id, -1); }}
                                                    className="h-9 w-9 bg-white rounded-xl shadow-sm flex items-center justify-center hover:bg-zinc-50 active:scale-95 transition-all"
                                                >
                                                    <Minus className="h-4 w-4 text-zinc-900" />
                                                </button>
                                                <span className="font-black text-lg text-zinc-900">{selected.quantity}</span>
                                                <button
                                                    type="button"
                                                    onClick={(e) => { e.stopPropagation(); updateProductQuantity(product.id, 1); }}
                                                    className="h-9 w-9 bg-white rounded-xl shadow-sm flex items-center justify-center hover:bg-zinc-50 active:scale-95 transition-all"
                                                >
                                                    <Plus className="h-4 w-4 text-zinc-900" />
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>

                    {/* Categorías de Promo */}
                    <Card className="rounded-[3rem] border-none shadow-[0_20px_50px_rgba(0,0,0,0.05)] bg-white overflow-hidden">
                        <CardHeader className="p-10 pb-6 flex flex-row justify-between items-center">
                            <div>
                                <CardTitle className="text-xl font-black uppercase tracking-widest text-zinc-900">Categorías de Promo</CardTitle>
                                <CardDescription className="font-bold">¿Dónde aparecerá esta oferta?</CardDescription>
                            </div>
                            <LayoutGrid className="h-8 w-8 text-zinc-200" />
                        </CardHeader>
                        <CardContent className="p-10 pt-0 flex flex-wrap gap-3">
                            {categories.map(cat => {
                                const isSelected = selectedCategories.includes(cat.id);
                                return (
                                    <button
                                        key={cat.id}
                                        type="button"
                                        onClick={() => setSelectedCategories(prev =>
                                            prev.includes(cat.id) ? prev.filter(c => c !== cat.id) : [...prev, cat.id]
                                        )}
                                        className={`px-8 py-4 rounded-[1.5rem] font-black text-sm transition-all border-2 flex items-center gap-3 ${isSelected
                                            ? 'bg-zinc-900 text-white border-zinc-900 shadow-xl shadow-zinc-200'
                                            : 'bg-zinc-50 text-zinc-500 border-zinc-100 hover:border-zinc-200'
                                            }`}
                                    >
                                        {cat.nombre}
                                        {isSelected && <Check className="h-4 w-4 stroke-[3px]" />}
                                    </button>
                                );
                            })}
                        </CardContent>
                    </Card>

                    {/* Price & Discount logic Card (NOW AT THE BOTTOM) */}
                    <Card className="rounded-[4rem] border-none shadow-[0_40px_80px_rgba(0,0,0,0.1)] overflow-hidden bg-white border-4 border-zinc-900/5">
                        <div className="grid grid-cols-1 lg:grid-cols-2">
                            <div className="p-12 space-y-8 bg-zinc-900 text-white">
                                <div className="flex items-center gap-4">
                                    <div className="h-16 w-16 bg-white/10 rounded-[2rem] flex items-center justify-center backdrop-blur-xl">
                                        <Tag className="h-8 w-8 text-emerald-400" />
                                    </div>
                                    <div>
                                        <CardTitle className="text-3xl font-black uppercase tracking-tighter">Precio Final</CardTitle>
                                        <CardDescription className="text-zinc-400 font-bold">Ajusta el precio de venta</CardDescription>
                                    </div>
                                </div>

                                <div className="space-y-4">
                                    <Label className="text-[0.65rem] font-black text-zinc-500 uppercase tracking-[0.3em] ml-2">Precio de Venta</Label>
                                    <div className="relative">
                                        <div className="absolute left-8 top-1/2 -translate-y-1/2 text-white/20 font-black text-5xl">$</div>
                                        <Input
                                            type="number"
                                            step="any"
                                            placeholder="0.00"
                                            className="h-28 rounded-[2.5rem] border-none bg-white/5 focus:bg-white/10 text-white pl-16 text-5xl font-black transition-all"
                                            value={formData.finalPrice}
                                            onChange={(e) => setFormData({ ...formData, finalPrice: e.target.value })}
                                        />
                                    </div>
                                </div>
                            </div>

                            <div className="p-12 flex flex-col justify-center space-y-8 bg-emerald-50">
                                <div className="space-y-6">
                                    <div className="flex justify-between items-center text-emerald-900/40 font-black text-sm uppercase tracking-widest">
                                        <span>Valor Total Productos</span>
                                        <span className="line-through text-2xl">${totalOriginalPrice.toLocaleString()}</span>
                                    </div>

                                    <div className="h-px bg-emerald-200/50 w-full" />

                                    <div className="flex justify-between items-end">
                                        <div className="space-y-1">
                                            <p className="text-xs font-black text-emerald-600 uppercase tracking-[0.2em]">Ahorro Real</p>
                                            <h3 className="text-5xl font-black text-emerald-700 tracking-tighter">
                                                -${calculatedDiscount.toLocaleString()}
                                            </h3>
                                        </div>
                                        <div className="bg-emerald-600 text-white px-8 py-4 rounded-[2rem] font-black text-3xl shadow-2xl shadow-emerald-200">
                                            {savingsPercentage}% OFF
                                        </div>
                                    </div>
                                </div>

                                <div className="p-6 bg-white/50 rounded-[2rem] border border-emerald-200 flex gap-4 items-center">
                                    <div className="h-12 w-12 bg-emerald-500 rounded-2xl flex items-center justify-center text-white shadow-lg">
                                        <Info className="h-6 w-6" />
                                    </div>
                                    <p className="text-xs font-bold text-emerald-800 leading-tight">
                                        Esta oferta representa un beneficio directo de **${calculatedDiscount.toLocaleString()}** para tus clientes habituales.
                                    </p>
                                </div>
                            </div>
                        </div>
                    </Card>
                </div>
            </div>

            <style jsx global>{`
                body {
                    background-color: #F8F9FA;
                }
                input[type="date"]::-webkit-calendar-picker-indicator {
                    filter: invert(0);
                    cursor: pointer;
                }
            `}</style>
        </form>
    );
}

"use client";

import { useState, useEffect, useCallback, use } from "react";
import { useRouter } from "next/navigation";
import {
    ChevronLeft,
    Edit3,
    Tag,
    Calendar,
    Image as ImageIcon,
    LayoutGrid,
    Package,
    Clock,
    DollarSign,
    Percent,
    ArrowRight,
    CheckCircle2,
    Loader2,
    CalendarDays,
    Info
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { toast } from "sonner";
import { getPromotionById } from "../../actions";
import Link from "next/link";

const DAYS_MAP: Record<string, string> = {
    "L": "Lunes",
    "M": "Martes",
    "X": "Miércoles",
    "J": "Jueves",
    "V": "Viernes",
    "S": "Sábado",
    "D": "Domingo",
};

export default function DetallePromocionPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const router = useRouter();
    const [loading, setLoading] = useState(true);
    const [promotion, setPromotion] = useState<any>(null);

    const fetchData = useCallback(async () => {
        setLoading(true);
        try {
            const res = await getPromotionById(id);
            if (res.success) {
                setPromotion(res.data);
            } else {
                toast.error(res.error || "No se pudo encontrar la promoción");
                router.push("/admin/dashboard/productos");
            }
        } catch (error) {
            console.error("Error fetching promotion:", error);
            toast.error("Error de conexión");
        } finally {
            setLoading(false);
        }
    }, [id, router]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    if (loading) {
        return (
            <div className="flex h-[80vh] items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-zinc-400" />
            </div>
        );
    }

    if (!promotion) return null;

    const daysList = promotion.daysOfWeek ? promotion.daysOfWeek.split(",") : [];

    // Calculate final price (total - discount)
    const totalOriginal = promotion.items?.reduce((sum: number, item: any) =>
        sum + (Number(item.product?.precio || 0) * item.quantity), 0) || 0;
    const finalPrice = totalOriginal - Number(promotion.discountValue);
    const savingsPercentage = totalOriginal > 0 ? Math.round((Number(promotion.discountValue) / totalOriginal) * 100) : 0;

    return (
        <div className="flex flex-col gap-10 p-12 bg-[#F8F9FA] min-h-screen w-full">
            {/* Header */}
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 sticky top-0 z-20 bg-[#F8F9FA]/90 backdrop-blur-xl py-6 -mt-12 border-b border-zinc-100">
                <div className="flex items-center gap-6">
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => router.push("/admin/dashboard/productos")}
                        className="h-14 w-14 rounded-[1.5rem] bg-white shadow-sm border border-zinc-200 hover:border-zinc-900 transition-all"
                    >
                        <ChevronLeft className="h-7 w-7 text-zinc-900" />
                    </Button>
                    <div>
                        <div className="flex items-center gap-3 mb-1">
                            <Badge className="bg-emerald-50 text-emerald-600 border-none font-bold text-[0.6rem] px-2 py-0.5 rounded-full">PROMOCIÓN ACTIVA</Badge>
                            <span className="text-zinc-300 text-xs font-bold uppercase tracking-widest">ID: {promotion.id.slice(-8)}</span>
                        </div>
                        <h1 className="text-4xl font-black text-zinc-900 tracking-tight">{promotion.name}</h1>
                    </div>
                </div>

                <div className="flex items-center gap-4">
                    <Link href={`/admin/dashboard/productos/promociones/${id}/editar`}>
                        <Button
                            className="rounded-[2rem] bg-zinc-900 text-white hover:bg-zinc-800 transition-all font-black h-14 px-10 text-lg shadow-2xl shadow-zinc-300"
                        >
                            <Edit3 className="h-5 w-5 mr-3" />
                            Editar Oferta
                        </Button>
                    </Link>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                {/* Left: Graphic & Summary */}
                <div className="xl:col-span-7 space-y-10">
                    <Card className="rounded-[4rem] border-none shadow-[0_40px_80px_rgba(0,0,0,0.05)] overflow-hidden bg-white">
                        <div className="aspect-[21/9] w-full relative group">
                            {promotion.imagen ? (
                                <img src={promotion.imagen} alt={promotion.name} className="h-full w-full object-cover" />
                            ) : (
                                <div className="h-full w-full bg-zinc-50 flex items-center justify-center">
                                    <ImageIcon className="h-20 w-20 text-zinc-100" />
                                </div>
                            )}
                            <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent flex flex-col justify-end p-12">
                                <h2 className="text-4xl font-black text-white mb-2">{promotion.name}</h2>
                                <p className="text-white/80 text-lg font-medium max-w-2xl">{promotion.description || "Sin descripción proporcionada"}</p>
                            </div>
                        </div>

                        <CardContent className="p-12">
                            <h3 className="text-xl font-black text-zinc-900 mb-8 uppercase tracking-widest flex items-center gap-3">
                                <Package className="h-6 w-6 text-zinc-400" />
                                Productos Incluidos
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                {promotion.items?.map((item: any) => (
                                    <div key={item.id} className="flex items-center gap-5 p-5 bg-zinc-50 rounded-[2rem] border border-zinc-100 group transition-all hover:bg-white hover:shadow-xl hover:border-transparent">
                                        <div className="h-20 w-20 rounded-[1.5rem] overflow-hidden bg-white shadow-sm flex-shrink-0">
                                            {item.product?.imagen ? (
                                                <img src={item.product.imagen} alt={item.product.nombre} className="h-full w-full object-cover" />
                                            ) : (
                                                <div className="h-full w-full flex items-center justify-center">
                                                    <Tag className="h-8 w-8 text-zinc-100" />
                                                </div>
                                            )}
                                        </div>
                                        <div>
                                            <div className="flex items-center gap-2 mb-1">
                                                <span className="h-6 w-6 bg-zinc-900 text-white rounded-lg flex items-center justify-center font-black text-xs leading-none">
                                                    {item.quantity}
                                                </span>
                                                <h4 className="font-black text-zinc-900 text-lg uppercase tracking-tight">{item.product?.nombre}</h4>
                                            </div>
                                            <p className="text-zinc-400 font-bold text-xs uppercase tracking-widest">${Number(item.product?.precio || 0).toLocaleString()} c/u</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                        {/* Categories */}
                        <Card className="rounded-[3rem] border-none shadow-[0_20px_40px_rgba(0,0,0,0.03)] bg-white overflow-hidden">
                            <CardHeader className="p-10 pb-0">
                                <CardTitle className="text-lg font-black uppercase tracking-widest text-zinc-400">Visibilidad</CardTitle>
                            </CardHeader>
                            <CardContent className="p-10 flex flex-wrap gap-2">
                                {promotion.categories?.length > 0 ? (
                                    promotion.categories.map((cat: any) => (
                                        <Badge key={cat.id} className="bg-zinc-100 text-zinc-900 hover:bg-zinc-200 border-none px-6 py-3 rounded-2xl font-black text-sm uppercase tracking-tight">
                                            {cat.nombre}
                                        </Badge>
                                    ))
                                ) : (
                                    <p className="text-zinc-300 font-bold italic">No hay categorías asignadas</p>
                                )}
                            </CardContent>
                        </Card>

                        {/* Status Info */}
                        <Card className="rounded-[3rem] border-none shadow-[0_20px_40px_rgba(0,0,0,0.03)] bg-zinc-900 text-white overflow-hidden">
                            <CardHeader className="p-10 pb-0">
                                <CardTitle className="text-lg font-black uppercase tracking-widest text-white/40">Estado de Operación</CardTitle>
                            </CardHeader>
                            <CardContent className="p-10">
                                <div className="flex items-center gap-6">
                                    <div className={`h-16 w-16 rounded-[2rem] flex items-center justify-center ${promotion.isActive ? 'bg-emerald-500/20 text-emerald-400' : 'bg-red-500/20 text-red-400'}`}>
                                        <CheckCircle2 className="h-10 w-10" />
                                    </div>
                                    <div>
                                        <h4 className="text-3xl font-black tracking-tight">{promotion.isActive ? 'Pública' : 'Borrador'}</h4>
                                        <p className="text-white/40 font-bold text-sm">La oferta {promotion.isActive ? 'está disponible para clientes' : 'no es visible en el menú'}.</p>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                </div>

                {/* Right: Constraints & Pricing */}
                <div className="xl:col-span-5 space-y-10">
                    <Card className="rounded-[4rem] border-none shadow-[0_40px_80px_rgba(0,0,0,0.1)] overflow-hidden bg-white border-4 border-zinc-900/5">
                        <div className="flex flex-col">
                            <div className="p-12 space-y-10 bg-zinc-900 text-white">
                                <div className="flex items-center gap-6">
                                    <div className="h-20 w-20 bg-emerald-500 rounded-[2.5rem] flex items-center justify-center shadow-xl shadow-emerald-500/20">
                                        <Tag className="h-10 w-10 text-white" />
                                    </div>
                                    <div>
                                        <h2 className="text-4xl font-black tracking-tighter uppercase whitespace-nowrap">Precio de Oferta</h2>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className="text-emerald-400 font-black text-xl italic">{savingsPercentage}% OFF</span>
                                            <span className="text-zinc-500 font-black text-lg line-through ml-2">${totalOriginal.toLocaleString()}</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="text-center py-4 border-y border-white/10">
                                    <span className="text-7xl font-black tracking-tighter block">${finalPrice.toLocaleString()}</span>
                                    <span className="text-zinc-500 font-black uppercase tracking-[0.4em] text-xs mt-4 block">Precio Final al Cliente</span>
                                </div>

                                <div className="flex items-center gap-4 p-8 bg-white/5 rounded-[2.5rem] border border-white/5">
                                    <div className="h-12 w-12 bg-white/10 rounded-2xl flex items-center justify-center text-emerald-400">
                                        <DollarSign className="h-6 w-6" />
                                    </div>
                                    <p className="text-sm font-bold text-white/60">
                                        Generando un ahorro directo de <span className="text-white font-black">${Number(promotion.discountValue).toLocaleString()}</span> comparado con compras individuales.
                                    </p>
                                </div>
                            </div>

                            <div className="p-12 space-y-12">
                                <div className="space-y-6">
                                    <h3 className="text-xl font-black text-zinc-900 uppercase tracking-widest flex items-center gap-3">
                                        <CalendarDays className="h-6 w-6 text-zinc-300" />
                                        Disponibilidad Temporal
                                    </h3>
                                    <div className="grid grid-cols-2 gap-6 pb-6 border-b border-zinc-50">
                                        <div className="space-y-2">
                                            <p className="text-[0.65rem] font-black text-zinc-400 uppercase tracking-widest">Desde</p>
                                            <p className="text-xl font-black text-zinc-900 italic">
                                                {promotion.startDate ? new Date(promotion.startDate).toLocaleDateString() : 'Sin fecha'}
                                            </p>
                                        </div>
                                        <div className="space-y-2">
                                            <p className="text-[0.65rem] font-black text-zinc-400 uppercase tracking-widest">Hasta</p>
                                            <p className="text-xl font-black text-zinc-900 italic">
                                                {promotion.endDate ? new Date(promotion.endDate).toLocaleDateString() : 'Sin fecha'}
                                            </p>
                                        </div>
                                    </div>

                                    <div className="space-y-4 pt-4">
                                        <p className="text-[0.65rem] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-2">
                                            <Clock className="h-3 w-3" />
                                            Días habilitados
                                        </p>
                                        <div className="flex flex-wrap gap-2">
                                            {daysList.length > 0 ? daysList.map((val: string) => (
                                                <div key={val} className="px-5 py-3 rounded-2xl bg-zinc-50 text-zinc-900 border border-zinc-100 font-black text-sm transition-all hover:bg-zinc-100 uppercase tracking-tighter">
                                                    {DAYS_MAP[val] || val}
                                                </div>
                                            )) : (
                                                <p className="text-sm font-bold text-zinc-400 italic">Habilitada todos los días</p>
                                            )}
                                        </div>
                                    </div>
                                </div>

                                <div className="flex gap-4 p-8 bg-zinc-50 rounded-[3rem] border border-zinc-100">
                                    <div className="h-10 w-10 bg-white rounded-xl shadow-sm flex items-center justify-center text-zinc-400 flex-shrink-0">
                                        <Info className="h-5 w-5" />
                                    </div>
                                    <p className="text-xs font-bold text-zinc-500 leading-relaxed italic">
                                        Asegúrate de que los ingredientes para los productos incluidos en esta promoción estén siempre disponibles en cocina para evitar cancelaciones.
                                    </p>
                                </div>
                            </div>
                        </div>
                    </Card>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback, useMemo, useRef } from "react";
import { useRouter } from "next/navigation";
import {
    ChevronLeft,
    Save,
    Tag,
    Calendar,
    Image as ImageIcon,
    LayoutGrid,
    Package,
    Plus,
    X,
    Check,
    Search,
    Loader2,
    AlertCircle,
    Info,
    Clock,
    DollarSign,
    Percent,
    Upload,
    Minus
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { getCategories, getProducts, createPromotion } from "../../actions";
import Link from "next/link";

interface SelectionItem {
    id: string;
    nombre: string;
    precio: number;
    imagen?: string | null;
    categoryId: string;
}

interface SelectedProduct {
    id: string;
    quantity: number;
}

const DAYS = [
    { label: "Lun", value: "L" },
    { label: "Mar", value: "M" },
    { label: "Mié", value: "X" },
    { label: "Jue", value: "J" },
    { label: "Vie", value: "V" },
    { label: "Sáb", value: "S" },
    { label: "Dom", value: "D" },
];

export default function NuevaPromocionPage() {
    const router = useRouter();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [loading, setLoading] = useState(false);
    const [fetchingData, setFetchingData] = useState(true);

    const [categories, setCategories] = useState<any[]>([]);
    const [products, setProducts] = useState<SelectionItem[]>([]);

    const [formData, setFormData] = useState({
        name: "",
        description: "",
        code: "",
        finalPrice: "",
        startDate: "",
        endDate: "",
        imagen: "",
        isActive: true,
    });

    const [selectedProducts, setSelectedProducts] = useState<SelectedProduct[]>([]);
    const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
    const [selectedDays, setSelectedDays] = useState<string[]>([]);

    const [productSearch, setProductSearch] = useState("");
    const [previewImage, setPreviewImage] = useState<string | null>(null);

    const fetchData = useCallback(async () => {
        try {
            setFetchingData(true);
            const [catRes, prodRes] = await Promise.all([getCategories(), getProducts()]);
            if (catRes.success) {
                const promoCats = catRes.data.filter((c: any) =>
                    c.nombre.toLowerCase().includes("promo")
                );
                setCategories(promoCats.length > 0 ? promoCats : catRes.data);
            }
            if (prodRes.success) setProducts(prodRes.data);
        } catch (error) {
            console.error("Error fetching data:", error);
            toast.error("Error al cargar datos necesarios");
        } finally {
            setFetchingData(false);
        }
    }, []);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const totalOriginalPrice = useMemo(() => {
        return selectedProducts.reduce((sum, sp) => {
            const product = products.find(p => p.id === sp.id);
            return sum + (product ? Number(product.precio) * sp.quantity : 0);
        }, 0);
    }, [selectedProducts, products]);

    const calculatedDiscount = useMemo(() => {
        const final = Number(formData.finalPrice) || 0;
        if (totalOriginalPrice === 0 || final === 0) return 0;
        return Math.max(0, totalOriginalPrice - final);
    }, [totalOriginalPrice, formData.finalPrice]);

    const savingsPercentage = useMemo(() => {
        if (totalOriginalPrice === 0 || calculatedDiscount === 0) return 0;
        return Math.round((calculatedDiscount / totalOriginalPrice) * 100);
    }, [totalOriginalPrice, calculatedDiscount]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name) {
            toast.error("El nombre de la promoción es obligatorio");
            return;
        }

        if (selectedProducts.length === 0) {
            toast.error("Debes seleccionar al menos un producto");
            return;
        }

        setLoading(true);
        try {
            const res = await createPromotion({
                ...formData,
                discountType: "FIXED_AMOUNT",
                discountValue: calculatedDiscount,
                daysOfWeek: selectedDays.join(","),
                items: selectedProducts.map(p => ({ productId: p.id, quantity: p.quantity })),
                categoryIds: selectedCategories,
            });

            if (res.success) {
                toast.success("Promoción creada satisfactoriamente");
                router.push("/admin/dashboard/productos");
            } else {
                toast.error(res.error || "Error al crear la promoción");
            }
        } catch (error) {
            toast.error("Error inesperado");
        } finally {
            setLoading(false);
        }
    };

    const toggleProduct = (id: string) => {
        setSelectedProducts(prev => {
            const existing = prev.find(p => p.id === id);
            if (existing) {
                return prev.filter(p => p.id !== id);
            } else {
                return [...prev, { id, quantity: 1 }];
            }
        });
    };

    const updateProductQuantity = (id: string, delta: number) => {
        setSelectedProducts(prev => prev.map(p => {
            if (p.id === id) {
                const newQty = Math.max(1, p.quantity + delta);
                return { ...p, quantity: newQty };
            }
            return p;
        }));
    };

    const toggleDay = (val: string) => {
        setSelectedDays(prev =>
            prev.includes(val) ? prev.filter(d => d !== val) : [...prev, val]
        );
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setPreviewImage(reader.result as string);
                setFormData({ ...formData, imagen: reader.result as string });
            };
            reader.readAsDataURL(file);
        }
    };

    if (fetchingData) {
        return (
            <div className="flex h-[80vh] items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-zinc-400" />
            </div>
        );
    }

    const filteredProducts = products.filter(p =>
        p.nombre.toLowerCase().includes(productSearch.toLowerCase())
    );

    return (
        <form onSubmit={handleSubmit} className="flex flex-col gap-8 p-12 bg-[#F8F9FA] min-h-screen w-full">
            {/* Header section - Full Width */}
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 sticky top-0 z-20 bg-[#F8F9FA]/90 backdrop-blur-xl py-6 -mt-12 border-b border-zinc-100">
                <div className="flex items-center gap-6">
                    <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        onClick={() => router.back()}
                        className="h-14 w-14 rounded-[1.5rem] bg-white shadow-sm border border-zinc-200 hover:border-zinc-900 transition-all hover:scale-105 active:scale-95"
                    >
                        <ChevronLeft className="h-7 w-7 text-zinc-900" />
                    </Button>
                    <div>
                        <h1 className="text-4xl font-black text-zinc-900 tracking-tight">Nueva Promoción</h1>
                        <p className="text-zinc-500 text-lg font-medium opacity-70 italic">Diseña una oferta irresistible para tu menú</p>
                    </div>
                </div>

                <div className="flex items-center gap-4 w-full lg:w-auto">
                    <Button
                        type="button"
                        variant="outline"
                        onClick={() => router.back()}
                        className="flex-1 lg:flex-none rounded-[2rem] border-zinc-200 text-zinc-500 hover:bg-white transition-all font-bold h-14 px-10 text-lg"
                    >
                        Descartar
                    </Button>
                    <Button
                        type="submit"
                        disabled={loading}
                        className="flex-1 lg:flex-none rounded-[2rem] bg-zinc-900 text-white hover:bg-zinc-800 transition-all font-black h-14 px-12 text-lg shadow-2xl shadow-zinc-300 transform motion-safe:hover:-translate-y-1 active:scale-95"
                    >
                        {loading ? <Loader2 className="h-6 w-6 animate-spin mr-3" /> : <Save className="h-6 w-6 mr-3" />}
                        Publicar Oferta
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                {/* Left Column - Configuration (Basic Info & Vigencia) */}
                <div className="xl:col-span-4 space-y-10">
                    {/* Basic Info */}
                    <Card className="rounded-[3rem] border-none shadow-[0_20px_50px_rgba(0,0,0,0.05)] overflow-hidden bg-white">
                        <CardHeader className="p-10 pb-0">
                            <Badge className="w-fit bg-zinc-900 text-white font-black px-4 py-1 rounded-full text-xs">PASO 1</Badge>
                            <h2 className="text-2xl font-black text-zinc-900">Información General</h2>
                        </CardHeader>
                        <CardContent className="p-10 space-y-8">
                            <div className="space-y-3">
                                <Label className="text-xs font-black text-zinc-400 uppercase tracking-[0.2em] ml-2">Nombre de la Promo</Label>
                                <Input
                                    placeholder="Ej: Mega Combo Familiar"
                                    className="h-16 rounded-[1.5rem] border-zinc-100 bg-zinc-50 font-bold text-xl px-6 focus:border-zinc-900 focus:ring-0"
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                                />
                            </div>

                            <div className="space-y-3">
                                <Label className="text-xs font-black text-zinc-400 uppercase tracking-[0.2em] ml-2">Descripción</Label>
                                <Textarea
                                    placeholder="Cuéntale a tus clientes qué incluye..."
                                    className="min-h-[120px] rounded-[2rem] border-zinc-100 bg-zinc-50 font-medium p-6 text-lg focus:border-zinc-900 focus:ring-0 italic"
                                    value={formData.description}
                                    onChange={e => setFormData({ ...formData, description: e.target.value })}
                                />
                            </div>

                            <div className="space-y-4">
                                <Label className="text-xs font-black text-zinc-400 uppercase tracking-[0.2em] ml-2">Imagen Publicitaria</Label>
                                <div
                                    onClick={() => fileInputRef.current?.click()}
                                    className="relative h-64 w-full rounded-[2.5rem] border-4 border-dashed border-zinc-100 hover:border-zinc-900 transition-all bg-zinc-50 flex flex-col items-center justify-center gap-4 cursor-pointer overflow-hidden group"
                                >
                                    {previewImage ? (
                                        <>
                                            <img src={previewImage} alt="Preview" className="h-full w-full object-cover" />
                                            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center transition-all">
                                                <Upload className="h-10 w-10 text-white" />
                                            </div>
                                        </>
                                    ) : (
                                        <>
                                            <div className="h-20 w-20 bg-white rounded-3xl shadow-lg flex items-center justify-center">
                                                <Upload className="h-10 w-10 text-zinc-400" />
                                            </div>
                                            <div className="text-center">
                                                <p className="font-black text-zinc-900">Seleccionar Archivo</p>
                                                <p className="text-xs text-zinc-400 font-bold uppercase tracking-widest mt-1">PNG, JPG hasta 5MB</p>
                                            </div>
                                        </>
                                    )}
                                    <input
