import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

import { serializePrisma } from '@/lib/utils';

export async function GET(_request: NextRequest) {
    try {
        const categories = await prisma.category.findMany({
            where: {
                deletedAt: null,
            },
            orderBy: [
                { orden: "asc" },
                { nombre: "asc" },
            ],
        });

        return NextResponse.json({
            success: true,
            data: serializePrisma(categories)
        });

    } catch (error) {
        console.error('Categories API Error:', error);
        return NextResponse.json(
            { success: false, error: 'Internal Server Error' },
            { status: 500 }
        );
    }
}

"use client";

import { useCart } from "@/providers/CartProvider";
import { CartDrawer } from "@/components/cart/CartDrawer";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Search, ShoppingCart, User, Menu, Pizza, Coffee, IceCream, Plus, Loader2 } from "lucide-react";
import Link from "next/link";
import { useState, useEffect, useCallback } from "react";
import { Category, Product } from "@prisma/client";
import { MenuSkeleton } from "@/components/menu/MenuSkeleton";

export default function CatalogPage() {
    const [categories, setCategories] = useState<Category[]>([]);
    const [products, setProducts] = useState<Product[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [activeCategory, setActiveCategory] = useState('Todas');
    const [searchQuery, setSearchQuery] = useState("");
    const { addItem } = useCart();

    const refreshData = useCallback(async () => {
        setIsLoading(true);
        try {
            const [catRes, prodRes] = await Promise.all([
                fetch('/api/categorias').then(res => res.json()),
                fetch('/api/productos').then(res => res.json())
            ]);

            if (catRes.success) setCategories(catRes.data as Category[]);
            if (prodRes.success) setProducts(prodRes.data as Product[]);
        } catch (error) {
            console.error("Error fetching menu data:", error);
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        refreshData();
    }, [refreshData]);

    const filteredProducts = products.filter(product => {
        const category = categories.find(c => c.id === product.categoryId);
        const matchesCategory = activeCategory === 'Todas' || (category && category.nombre === activeCategory);
        const matchesSearch = product.nombre.toLowerCase().includes(searchQuery.toLowerCase());
        return matchesCategory && matchesSearch;
    });

    const handleAddToCart = (product: Product) => {
        addItem(product);
        toast.success(`${product.nombre} agregado al carrito`, {
            duration: 2000,
            position: 'top-center'
        });
    };

    if (isLoading) {
        return <MenuSkeleton />;
    }

    return (
        <div className="min-h-screen bg-background pb-20">
            {/* Mobile Header - Sticky */}
            <header className="sticky top-0 z-50 bg-background/80 backdrop-blur-md border-b border-border/50 shadow-sm">
                <div className="max-w-md mx-auto px-4 py-3 flex items-center justify-between gap-4">
                    <div className="font-outfit font-bold text-xl text-primary tracking-tight">
                        Trattoria
                    </div>

                    <div className="flex-1 max-w-[200px]">
                        <div className="relative">
                            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                            <Input
                                type="search"
                                placeholder="Buscar..."
                                className="pl-9 h-9 rounded-full bg-secondary/50 border-none focus:ring-1 focus:ring-primary/20"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>
                    </div>

                    <Link href="/admin/dashboard">
                        <Button variant="ghost" size="icon" className="rounded-full text-foreground/80 hover:text-primary hover:bg-primary/10">
                            <User className="h-5 w-5" />
                        </Button>
                    </Link>
                </div>

                {/* Categories Scroll */}
                <div className="max-w-md mx-auto overflow-x-auto pb-3 px-4 scrollbar-hide">
                    <div className="flex gap-2 w-max">
                        <button
                            onClick={() => setActiveCategory('Todas')}
                            className={`
                flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all duration-200 border
                ${activeCategory === 'Todas'
                                    ? 'bg-primary text-primary-foreground border-primary shadow-lg shadow-primary/20 scale-105'
                                    : 'bg-card text-muted-foreground border-border hover:border-primary/30 hover:bg-secondary/50'}
              `}
                        >
                            <Menu className="h-4 w-4" />
                            Todas
                        </button>
                        {categories.map((cat) => (
                            <button
                                key={cat.id}
                                onClick={() => setActiveCategory(cat.nombre)}
                                className={`
                  flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all duration-200 border
                  ${activeCategory === cat.nombre
                                        ? 'bg-primary text-primary-foreground border-primary shadow-lg shadow-primary/20 scale-105'
                                        : 'bg-card text-muted-foreground border-border hover:border-primary/30 hover:bg-secondary/50'}
                `}
                            >
                                {cat.imagen && (
                                    <img
                                        src={cat.imagen}
                                        alt=""
                                        className="h-4 w-4 object-cover rounded-full"
                                        onError={(e) => (e.currentTarget.style.display = 'none')}
                                    />
                                )}
                                {cat.nombre}
                            </button>
                        ))}
                    </div>
                </div>
            </header>

            {/* Decorative Background Blobs */}
            <div className="fixed top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
                <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-primary/3 rounded-full blur-3xl opacity-60" />
                <div className="absolute bottom-[20%] left-[-10%] w-[60%] h-[60%] bg-secondary/40 rounded-full blur-3xl opacity-60" />
            </div>

            {/* Main Content */}
            <main className="max-w-md mx-auto px-4 py-6 space-y-6">

                {/* Promotional Banner (Mobile First Hero) */}
                {activeCategory === 'Todas' && !searchQuery && categories.some(c => c.esPromocion) && (
                    <div className="relative overflow-hidden rounded-[2rem] bg-primary text-primary-foreground p-6 shadow-xl shadow-primary/20 mb-8 border-4 border-white/10">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-2xl -mr-10 -mt-10" />
                        <div className="relative z-10">
                            <span className="inline-block px-3 py-1 rounded-full bg-white/20 text-xs font-semibold backdrop-blur-sm mb-3">
                                Promociones 🔥
                            </span>
                            <h2 className="text-2xl font-bold leading-tight mb-2">¡Descubre nuestras<br />ofertas especiales!</h2>
                            <p className="text-primary-foreground/90 text-sm mb-4 max-w-[80%]">
                                Explora la sección de promociones para encontrar los mejores combos.
                            </p>
                            <Button
                                onClick={() => {
                                    const promoCat = categories.find(c => c.esPromocion);
                                    if (promoCat) setActiveCategory(promoCat.nombre);
                                }}
                                size="sm"
                                className="bg-white text-primary hover:bg-white/90 rounded-xl font-bold px-6 shadow-lg"
                            >
                                Ver Promos
                            </Button>
                        </div>
                    </div>
                )}

                {/* Section Title */}
                <div className="flex items-center justify-between">
                    <h3 className="text-lg font-bold text-foreground">
                        {activeCategory === 'Todas' ? 'Nuestro Menú' : activeCategory}
                    </h3>
                    <span className="text-xs text-muted-foreground font-medium bg-secondary/50 px-2 py-1 rounded-lg">
                        {filteredProducts.length} productos
                    </span>
                </div>

                {/* Products Grid */}
                <div className="grid grid-cols-1 gap-4">
                    {filteredProducts.map((product) => (
                        <div
                            key={product.id}
                            className="group relative bg-card rounded-[1.5rem] p-3 flex gap-4 border border-border/60 hover:border-primary/40 transition-all hover:shadow-lg hover:shadow-primary/5 active:scale-[0.99] overflow-hidden"
                        >
                            {/* Product Image */}
                            <div className="h-28 w-28 flex-shrink-0 relative rounded-2xl overflow-hidden bg-secondary/30">
                                <img
                                    src={product.imagen || "https://images.unsplash.com/photo-1513104890138-7c749659a591?w=400"}
                                    alt={product.nombre}
                                    className="h-full w-full object-cover transition-transform duration-500 group-hover:scale-110"
                                />
                            </div>

                            {/* Content */}
                            <div className="flex flex-col flex-1 justify-between py-1">
                                <div>
                                    <div className="flex justify-between items-start">
                                        <h4 className="font-bold text-foreground text-lg leading-tight mb-1">{product.nombre}</h4>
                                    </div>
                                    <p className="text-xs text-muted-foreground line-clamp-2 leading-relaxed">
                                        {product.descripcion}
                                    </p>
                                </div>

                                <div className="flex items-end justify-between mt-2">
                                    <div className="flex flex-col">
                                        <span className="text-lg font-bold text-primary font-outfit">
                                            ${Number(product.precio).toLocaleString('es-CL')}
                                        </span>
                                        {product.stockActual <= 5 && product.stockActual > 0 && (
                                            <span className="text-[10px] text-amber-600 font-bold uppercase mt-1">¡Quedan pocos!</span>
                                        )}
                                    </div>
                                    <Button
                                        size="icon"
                                        onClick={() => handleAddToCart(product)}
                                        className="h-9 w-9 rounded-xl bg-foreground text-background hover:bg-primary hover:text-white transition-colors shadow-md"
                                    >
                                        <Plus className="h-5 w-5" />
                                    </Button>
                                </div>
                            </div>
                        </div>
                    ))}

                    {filteredProducts.length === 0 && (
                        <div className="text-center py-12 text-muted-foreground">
                            <p>No encontramos productos en esta categoría :(</p>
                        </div>
                    )}
                </div>
            </main>

            {/* Bottom Navigation (Floating Cart) */}
            <div className="fixed bottom-6 left-0 right-0 px-4 z-40 pointer-events-none">
                <div className="max-w-md mx-auto pointer-events-auto flex justify-center">
                    <CartDrawer />
                </div>
            </div>
        </div>
    );
}

"use client";

import { useCart } from "@/providers/CartProvider";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetFooter, SheetTrigger } from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { ShoppingCart, Minus, Plus, Trash2, ShoppingBag, ArrowLeft, Send } from "lucide-react";
import { Separator } from "@/components/ui/separator";
import { useState } from "react";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { createPublicOrder } from "@/app/actions/orders";
import { toast } from "sonner";
import { Loader2 } from "lucide-react";

export function CartDrawer() {
    const { items, removeItem, updateQuantity, totalPrice, totalItems, clearCart } = useCart();
    const [step, setStep] = useState<'cart' | 'checkout'>('cart');
    const [formData, setFormData] = useState({
        nombre: '',
        direccion: '',
        metodoPago: 'Transferencia'
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleConfirmOrder = async () => {
        if (isSubmitting) return;

        setIsSubmitting(true);
        try {
            // 1. Create order in database
            const result = await createPublicOrder({
                clienteNombre: formData.nombre,
                clienteDireccion: formData.direccion,
                metodoPago: formData.metodoPago,
                total: totalPrice,
                items: items.map(item => ({
                    productId: item.id,
                    cantidad: item.quantity,
                    precioUnitario: Number(item.precio),
                    nombreProduct: item.nombre
                }))
            });

            if (!result.success) {
                toast.error(result.error || "Error al procesar el pedido");
                return;
            }

            // WhatsApp notification number
            const WHATSAPP_NUMBER = "5493886033878";

            const cartItemsText = items.map(item =>
                `• ${item.nombre} x${item.quantity} - $${(Number(item.precio) * item.quantity).toLocaleString('es-CL')}`
            ).join('\n');

            const message = `*NUEVO PEDIDO #${result.orderNumber} - TRATTORIA*\n\n` +
                `*Datos del Cliente:*\n` +
                `👤 Nombre: ${formData.nombre}\n` +
                `📍 Dirección: ${formData.direccion}\n` +
                `💳 Pago: ${formData.metodoPago}\n\n` +
                `*Pedido:*\n${cartItemsText}\n\n` +
                `*TOTAL: $${totalPrice.toLocaleString('es-CL')}*\n\n` +
                `Por favor, confirma recepción.`;

            const encodedMessage = encodeURIComponent(message);
            const whatsappUrl = `https://wa.me/${WHATSAPP_NUMBER}?text=${encodedMessage}`;

            window.open(whatsappUrl, '_blank');

            // Clear cart and reset state
            clearCart();
            setStep('cart');
            setFormData({ nombre: '', direccion: '', metodoPago: 'Transferencia' });
            toast.success("¡Pedido enviado con éxito!");
        } catch (error) {
            console.error(error);
            toast.error("Ocurrió un error inesperado");
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <Sheet onOpenChange={(open) => { if (!open) setStep('cart'); }}>
            <SheetTrigger asChild>
                <Button
                    variant="default"
                    className="h-14 rounded-full px-6 flex items-center gap-3 bg-primary text-primary-foreground shadow-2xl shadow-primary/30 hover:shadow-primary/40 transition-all border-none"
                >
                    <div className="relative">
                        <ShoppingCart className="h-6 w-6" />
                        {totalItems > 0 && (
                            <span className="absolute -top-2 -right-2 bg-foreground text-background text-[10px] font-bold h-5 w-5 rounded-full flex items-center justify-center ring-2 ring-primary">
                                {totalItems}
                            </span>
                        )}
                    </div>
                    <div className="flex flex-col items-start leading-none">
                        <span className="text-[10px] opacity-80 font-medium uppercase tracking-wider">Tu Carrito</span>
                        <span className="text-sm font-bold">${totalPrice.toLocaleString('es-CL')}</span>
                    </div>
                </Button>
            </SheetTrigger>
            <SheetContent side="right" className="w-full sm:max-w-md flex flex-col p-0 bg-background border-none rounded-l-[2rem]">
                <SheetHeader className="p-6 pb-2">
                    <div className="flex items-center gap-3 mb-2">
                        {step === 'checkout' && (
                            <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8 rounded-full"
                                onClick={() => setStep('cart')}
                            >
                                <ArrowLeft className="h-5 w-5" />
                            </Button>
                        )}
                        <div className="h-10 w-10 rounded-xl bg-primary/10 flex items-center justify-center">
                            <ShoppingBag className="h-5 w-5 text-primary" />
                        </div>
                        <SheetTitle className="text-2xl font-bold font-outfit">
                            {step === 'cart' ? 'Mi Pedido' : 'Datos de Entrega'}
                        </SheetTitle>
                    </div>
                    <p className="text-sm text-muted-foreground">
                        {step === 'cart'
                            ? 'Revisa tus productos antes de confirmar'
                            : 'Completa la información para tu pedido'}
                    </p>
                </SheetHeader>

                <div className="flex-1 overflow-y-auto px-6 my-4 scrollbar-hide">
                    {items.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center text-center space-y-4">
                            <div className="h-20 w-20 rounded-full bg-secondary/50 flex items-center justify-center">
                                <ShoppingCart className="h-10 w-10 text-muted-foreground" />
                            </div>
                            <div className="space-y-1">
                                <p className="font-bold text-lg">Tu carrito está vacío</p>
                                <p className="text-sm text-muted-foreground">Explora nuestro menú y agrega tus platos favoritos</p>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            {step === 'cart' ? (
                                items.map((item) => (
                                    <div key={item.id} className="flex gap-4 group">
                                        <div className="h-20 w-20 rounded-2xl overflow-hidden bg-secondary/30 flex-shrink-0">
                                            <img
                                                src={item.imagen || "https://images.unsplash.com/photo-1513104890138-7c749659a591?w=200"}
                                                alt={item.nombre}
                                                className="h-full w-full object-cover"
                                            />
                                        </div>
                                        <div className="flex-1 flex flex-col justify-between py-0.5">
                                            <div className="flex justify-between gap-2">
                                                <h4 className="font-bold text-sm leading-tight line-clamp-2">{item.nombre}</h4>
                                                <button
                                                    onClick={() => removeItem(item.id)}
                                                    className="text-muted-foreground hover:text-destructive transition-colors"
                                                >
                                                    <Trash2 className="h-4 w-4" />
                                                </button>
                                            </div>

                                            <div className="flex items-center justify-between mt-2">
                                                <div className="flex items-center bg-secondary/50 rounded-lg p-1">
                                                    <button
                                                        onClick={() => updateQuantity(item.id, item.quantity - 1)}
                                                        className="h-7 w-7 flex items-center justify-center rounded-md hover:bg-background transition-colors"
                                                    >
                                                        <Minus className="h-3 w-3" />
                                                    </button>
                                                    <span className="w-8 text-center text-sm font-bold font-outfit">{item.quantity}</span>
                                                    <button
                                                        onClick={() => updateQuantity(item.id, item.quantity + 1)}
                                                        className="h-7 w-7 flex items-center justify-center rounded-md hover:bg-background transition-colors"
                                                    >
                                                        <Plus className="h-3 w-3" />
                                                    </button>
                                                </div>
                                                <span className="font-bold text-primary">
                                                    ${(Number(item.precio) * item.quantity).toLocaleString('es-CL')}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                                    <div className="space-y-2">
                                        <Label htmlFor="nombre">Tu Nombre</Label>
                                        <Input
                                            id="nombre"
                                            name="nombre"
                                            placeholder="Ej. Juan Pérez"
                                            value={formData.nombre}
                                            onChange={handleInputChange}
                                            className="rounded-xl h-12"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="direccion">Dirección de Entrega</Label>
                                        <Input
                                            id="direccion"
                                            name="direccion"
                                            placeholder="Calle, Número, Departamento"
                                            value={formData.direccion}
                                            onChange={handleInputChange}
                                            className="rounded-xl h-12"
                                        />
                                    </div>
                                    <div className="space-y-3">
                                        <Label>Método de Pago</Label>
                                        <RadioGroup
                                            value={formData.metodoPago}
                                            onValueChange={(val: string) => setFormData(prev => ({ ...prev, metodoPago: val }))}
                                            className="flex flex-col gap-2"
                                        >
                                            <div className="flex items-center space-x-3 p-3 rounded-xl border border-border bg-card">
                                                <RadioGroupItem value="Transferencia" id="transferencia" />
                                                <Label htmlFor="transferencia" className="flex-1 cursor-pointer">Transferencia Electrónica</Label>
                                            </div>
                                            <div className="flex items-center space-x-3 p-3 rounded-xl border border-border bg-card">
                                                <RadioGroupItem value="Efectivo" id="efectivo" />
                                                <Label htmlFor="efectivo" className="flex-1 cursor-pointer">Efectivo al recibir</Label>
                                            </div>
                                        </RadioGroup>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                {items.length > 0 && (
                    <div className="p-6 bg-secondary/30 rounded-t-[2.5rem] space-y-4 shadow-[0_-10px_40px_rgba(0,0,0,0.05)]">
                        <div className="space-y-2">
                            <div className="flex justify-between text-sm">
                                <span className="text-muted-foreground">Productos ({totalItems})</span>
                                <span>${totalPrice.toLocaleString('es-CL')}</span>
                            </div>
                            <div className="flex justify-between text-sm">
                                <span className="text-muted-foreground">Envío</span>
                                <span className="text-green-600 font-medium">Gratis</span>
                            </div>
                            <Separator className="bg-border/50 my-2" />
                            <div className="flex justify-between items-end">
                                <span className="text-lg font-bold">Total</span>
                                <span className="text-2xl font-bold font-outfit text-primary">${totalPrice.toLocaleString('es-CL')}</span>
                            </div>
                        </div>

                        {step === 'cart' ? (
                            <Button
                                onClick={() => setStep('checkout')}
                                className="w-full h-14 rounded-2xl bg-primary hover:bg-primary/90 text-white font-bold text-lg shadow-xl shadow-primary/20 transition-all active:scale-[0.98]"
                            >
                                Continuar Pedido
                            </Button>
                        ) : (
                            <Button
                                onClick={handleConfirmOrder}
                                disabled={!formData.nombre || !formData.direccion || isSubmitting}
                                className="w-full h-14 rounded-2xl bg-green-600 hover:bg-green-700 text-white font-bold text-lg shadow-xl shadow-green-600/20 transition-all active:scale-[0.98] flex items-center justify-center gap-2"
                            >
                                {isSubmitting ? (
                                    <>
                                        <Loader2 className="h-5 w-5 animate-spin" />
                                        Procesando...
                                    </>
                                ) : (
                                    <>
                                        <Send className="h-5 w-5" />
                                        Confirmar vía WhatsApp
                                    </>
                                )}
                            </Button>
                        )}
                    </div>
                )}
            </SheetContent>
        </Sheet>
    );
}
